// Definition for singly-linked list node
class ListNode {
    constructor(val = 0, next = null) {
        this.val = val;   
        this.next = next;
    }
}

class Solution {
    /**
     * Adds two numbers represented by linked lists.
     * @param {ListNode} l1 - Head of the first linked list
     * @param {ListNode} l2 - Head of the second linked list
     * @returns {ListNode} Head of the resulting linked list
     */
    addTwoNumbers(l1, l2) {
        // Create a dummy node to simplify result list handling
        let dummy = new ListNode();
        // Pointer to the current node in the result list
        let temp = dummy; 
        // Carry from the previous addition
        let carry = 0;    

        // Loop until both lists are exhausted and carry is 0
        while (l1 !== null || l2 !== null || carry) {
        // Holds sum of current digits + carry
            let sum = 0; 

            // Add value from l1 if it exists
            if (l1 !== null) {
                sum += l1.val;
                l1 = l1.next;
            }

            // Add value from l2 if it exists
            if (l2 !== null) {
                sum += l2.val;
                l2 = l2.next;
            }

            // Add carry from previous step
            sum += carry;

            // Update carry for next iteration
            carry = Math.floor(sum / 10);

            // Create new node with digit value (sum % 10)
            temp.next = new ListNode(sum % 10);

            // Move temp forward
            temp = temp.next;
        }

        // Return the head of the result list (skipping dummy)
        return dummy.next;
    }
}
function createList(arr) {
    let head = new ListNode(arr[0]);
    let temp = head;
    for (let i = 1; i < arr.length; i++) {
        temp.next = new ListNode(arr[i]);
        temp = temp.next;
    }
    return head;
}

function printList(head) {
    let res = [];
    while (head) {
        res.push(head.val);
        head = head.next;
    }
    console.log(res.join(" -> "));
}

